const amqp = require('amqplib/callback_api');

// RabbitMQ server connection configuration
let queueName = 'payment-events';  // Replace with your queue name
let connStr = "amqp://localhost";   // Replace with the actual connection string for RabbitMQ

// Connect to RabbitMQ server
amqp.connect(connStr, (err, conn) => {
    if(err){
        console.log("Failed to connect", err); 
        return;
    }

    // Create channel and assert queue 
    conn.createChannel((err, ch) => {
        if(err){
            console.error('Failed to create a channel', err);  
            return;
        }
        
        ch.assertQueue(queueName, { durable: true }, (err, ok) => {
            if(err){
                console.log("Failed to assert queue", err); 
                return;
            }
            
            // Consume messages from the queue
            ch.consume(queueName, msg => {
                if(msg !== null){
                    let paymentData = JSON.parse(msg.content.toString());
                    
                    // Processing of payment event data depends on your business logic.
                    processPaymentEvent(paymentData);  
                  
                    // Acknowledge the message after processing it 
                    ch.ack(msg);
                }              
            });            
        });        
    });    
});

